#include <stdio.h>
struct Node {
    int data;
    struct Node* next;
};

struct Node* intersection(struct Node* head1, struct Node* head2) {
    if (head1 == NULL || head2 == NULL) return NULL;
    struct Node* ptr1 = head1;
    struct Node* ptr2 = head2;
    while (ptr1 != ptr2) {
        ptr1 = ptr1 == NULL ? head2 : ptr1->next;
        ptr2 = ptr2 == NULL ? head1 : ptr2->next;
    }
    return ptr1;
}

int main() {
    // Create linked lists
    struct Node* head1 = (struct Node*)malloc(sizeof(struct Node));
    head1->data = 1;
    head1->next = (struct Node*)malloc(sizeof(struct Node));
    head1->next->data = 2;
    head1->next->next = (struct Node*)malloc(sizeof(struct Node));
    head1->next->next->data = 3;
    head1->next->next->next = NULL;

    struct Node* head2 = (struct Node*)malloc(sizeof(struct Node));
    head2->data = 4;
    head2->next = head1->next;

    struct Node* intersectionNode = intersection(head1, head2);
    if (intersectionNode != NULL) printf("Intersection node value: %d\n", intersectionNode->data);
    else printf("No intersection\n");
    return 0;
}

