class Node {
    int data;
    Node next;
    Node(int val) {
        data = val;
        next = null;
    }
}

class Solution {
    Node intersection(Node head1, Node head2) {
        if (head1 == null || head2 == null) return null;
        Node ptr1 = head1;
        Node ptr2 = head2;
        while (ptr1 != ptr2) {
            ptr1 = ptr1 == null ? head2 : ptr1.next;
            ptr2 = ptr2 == null ? head1 : ptr2.next;
        }
        return ptr1;
    }
}

public class Main {
    public static void main(String[] args) {
        Solution sol = new Solution();
        // Create linked lists
        Node head1 = new Node(1);
        head1.next = new Node(2);
        head1.next.next = new Node(3);
        head1.next.next.next = null;

        Node head2 = new Node(4);
        head2.next = head1.next;

        Node intersectionNode = sol.intersection(head1, head2);
        if (intersectionNode != null) System.out.println("Intersection node value: " + intersectionNode.data);
        else System.out.println("No intersection");
    }
}

